import { Component, ElementRef, OnInit, ViewChild, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { CartService } from '../../Services/CartService';
import { CartModel, Status } from '../../Models/Cart';
import { FormsModule } from '@angular/forms';
import { jwtDecode } from 'jwt-decode';
import { ButtonModule } from 'primeng/button';
import { DataViewModule } from 'primeng/dataview';
import { TagModule } from 'primeng/tag';
import { SelectButtonModule } from 'primeng/selectbutton'; // עבור ה-p-selectbutton שצעק
import { NgClass, NgFor, CurrencyPipe } from '@angular/common'; // תוסיפי את אלו
import { InputNumberModule } from 'primeng/inputnumber';
import { Router } from '@angular/router';
import { GiftsService } from '../../Services/GiftsService';
import { MessageModule } from 'primeng/message';
import { RatingModule } from 'primeng/rating';
import { TableModule } from 'primeng/table';
import { DialogModule } from 'primeng/dialog';

interface Column {
  field: string;
  header: string;
}



@Component({
  selector: 'app-cart-comp',
  standalone: true,
  imports: [CommonModule, FormsModule, ButtonModule, DataViewModule, TagModule, SelectButtonModule, NgClass, NgFor, CurrencyPipe, InputNumberModule, MessageModule, RatingModule, TableModule, DialogModule],
  templateUrl: './cart-comp.html',
  styleUrl: './cart-comp.scss',
})
export class CartComp {
  // שימוש ב-Signal כמו בדוגמה של PrimeNG
  cartData = signal<CartModel | null>(null);
  paidOrders = signal<CartModel[]>([]);
  showPaidOrders = signal(false);

  confirmDialogVisible: boolean = false   // האם חלון האישור פתוח של התשלום
  totalToPay = signal(0);                 // הסכום הכולל להצגה



  cart: CartModel | null = null;
  userId: number | null = null;
  giftId: number | null = null;

  messages = signal<any[]>([]);
  @ViewChild('confettiCanvas') confettiCanvas?: ElementRef<HTMLCanvasElement>;




  constructor(private cartService: CartService, private router: Router, private giftService: GiftsService) { }

  ngOnInit() {
    this.addMessages();
    const token = localStorage.getItem('authToken');
    if (token) {
      try {
        const decodedToken: any = jwtDecode(token);
        console.log('Full Token Payload:', decodedToken); // תבדוק כאן איך קוראים לשדה של ה-ID
        // שליפת ה-ID לפי המפתח הארוך שמופיע בתמונה שלך
        const key = 'http://schemas.xmlsoap.org/ws/2005/05/identity/claims/nameidentifier';
        this.userId = decodedToken[key];
        // this.userId = decodedToken.id;
        if (this.userId) {
          this.loadCart();
        }
      }
      catch (error) {
        console.error('Invalid token:', error);
      }
    }
    else {
      console.log('No token found');
      // this.loadGuestCart(); // מציג סל אורח אם אין משתמש מחובר
    }
  }
  details(id: number) {
    this.router.navigate(['/gift', id]);
  }
  // טוען את הסל שלא שולם של המשתמש המחובר
  loadCart() {
    if (!this.userId) {
      this.loadGuestCart();
      return;
    }
    else {
      console.log("!!!!!!!!!!!!!!!!!");
    }
    this.cartService.GetUnpaidCartByUserId(this.userId).subscribe({
      next: (data) => {
        this.cartData.set(data);
        // this.cart = data;
        console.log(this.cartData());
      },
      error: (err) => console.error(err)
    });
  }

  // טוען את הסל של אורח מה-LS
  loadGuestCart() {
    // 1. קבל את המוצרים מה-LS
    const items = JSON.parse(localStorage.getItem('guestCart') || '[]');

    if (items.length === 0) {
      // אין מוצרים, הסל ריק
      this.cartData.set({
        id: 0,
        userId: 0,
        status: Status.Draft,
        items: []
      });
      return;
    }

    // 2. קבל את כל המתנות מה-API
    this.giftService.getGifts().subscribe(allGifts => {
      // 3. מיפוי המתנות מה-LS עם הפרטים המלאים
      const cartItems = items.map((i: any) => {
        const gift = allGifts.find(g => g.id === i.giftId);
        return {
          giftId: i.giftId,
          giftName: gift ? gift.name : 'Unknown Gift',
          quantity: i.quantity,
          ticketPrice: gift ? gift.ticketPrice : 0
        };
      });
      // 4. עדכון ה-Signal
      this.cartData.set({
        id: 0,
        userId: 0,
        status: Status.Draft,
        items: cartItems
      });
      console.log('Guest cart loaded:', this.cartData());
    }, err => {
      console.error('Error loading gifts for guest cart', err);
    });
  }

  // הוספת מתנה לסל
  addGift() {
    if (!this.giftId || !this.userId) {
      console.log("GIFTID");
      return;
    }
    this.cartService.AddGiftToCart({ userId: this.userId, giftId: this.giftId }).subscribe({
      next: (data) => {
        this.cart = data;
        console.log(this.cart);
        this.loadCart();
      },
      error: (err) => console.error(err)
    })
  }
  // פונקציה לקבלת הסגנון של התגית בהתאם למחיר
  getSeverity(item: any) {
    if (item.price > 100) return 'success';
    return 'info';
  }

  plusOne(item: any) {
    if (!this.userId) {
      const guestCart = JSON.parse(localStorage.getItem('guestCart') || '[]');
      const index = guestCart.findIndex((i: any) => i.giftId === item.giftId);
      if (index !== -1) {
        guestCart[index].quantity += 1;
      }
      localStorage.setItem('guestCart', JSON.stringify(guestCart));
      this.loadGuestCart(); // מעדכן את ה-Signal
      return;
    }
    this.cartService.PlusOne({ userId: this.userId, giftId: item.giftId }).subscribe({
      next: (data) => {
        this.cartData.set(data);
        this.loadCart();

      },
      error: (err) => console.error(err)
    });
  }

  minusOne(item: any) {
    if (item.quantity <= 1) return;

    if (!this.userId) {
      const guestCart = JSON.parse(localStorage.getItem('guestCart') || '[]');
      const index = guestCart.findIndex((i: any) => i.giftId === item.giftId);
      if (index !== -1) {
        guestCart[index].quantity -= 1;
        if (guestCart[index].quantity <= 0) {
          guestCart.splice(index, 1); // מוחק את הפריט אם הכמות היא 0
        }
      }
      localStorage.setItem('guestCart', JSON.stringify(guestCart));
      this.loadGuestCart(); // מעדכן את ה-Signal
      return;
    }
    this.cartService.MinusOne({ userId: this.userId, giftId: item.giftId }).subscribe({
      next: (data) => {
        this.cartData.set(data);
        this.loadCart();
      },
      error: (err) => console.error(err)
    });
  }

  deleteItem(item: any) {
    if (!this.userId) {
      const guestCart = JSON.parse(localStorage.getItem('guestCart') || '[]');
      const index = guestCart.findIndex((i: any) => i.giftId === item.giftId);
      if (index !== -1) {
        guestCart.splice(index, 1); // מוחק את הפריט מהסל של אורח
      }
      localStorage.setItem('guestCart', JSON.stringify(guestCart));
      this.loadGuestCart(); // מעדכן את ה-Signal
      return;
    }
    this.cartService.DeleteGiftFromCart(this.userId, item.giftId).subscribe({
      next: (data) => {
        this.cartData.set(data);
        this.loadCart();
      },
      error: (err) => console.error(err)
    });
  }
  goToAllGifts() {
    this.router.navigate(['/all-gifts']);
  }
  clearMessages() {
    this.messages.set([]);
  }

  addMessages() {
    this.messages.set([
      {
        severity: 'success',
        content: 'הוספת מתנה חדשה',
        action: 'newGift'
      },
      {
        severity: 'secondary',
        content: 'היסטורית הזמנות',
        action: 'oldOrders'
      },
      {
        severity: 'warning',
        content: 'הזמנה בתהליך',
        action: 'toPay'
      }
    ]);
  }
  onMessageClick(action: string) {
    if (action === 'newGift') this.goToAllGifts();
    if (action === 'oldOrders') this.oldOrders();
    if (action === 'toPay') this.showCurrentCart();
  }
  // הצגת הסל הנוכחי
  showCurrentCart() {
    this.showPaidOrders.set(false);
  }
  // הצגת ההזמנות הישנות ששולמו
  oldOrders() {
    console.log("Old Orders");
    if (!this.userId) {
      return;
    }
    this.showPaidOrders.set(true); // 👈 חשוב! בלי זה ה-HTML לא יראה את ההזמנות

    this.cartService.GetPaidCartByUserId(this.userId).subscribe({
      next: (data) => {
        if (data) {
          const ordersArray = Array.isArray(data) ? data : [data];
          this.paidOrders.set(ordersArray);   // ✅ מכניסים את ההזמנה למערך
          this.showPaidOrders.set(true); // ✅ מציגים את ההזמנות במקום הסל
        } else {
          this.paidOrders.set([]);
          this.showPaidOrders.set(true); // ✅ עדיין מציגים “אין הזמנות”

        }
      }
    });
  }
  // חישוב הסכום הכולל של הזמנה
  getOrderTotal(order: CartModel) {
    if (!order || !order.items) return 0;
    return order.items.reduce((sum, item) => sum + (item.ticketPrice * item.quantity), 0);
  }
  // ביצוע תשלום על הסל הנוכחי
  toPay() {
    console.log("To Pay");
    this.showPaidOrders.set(false);  // 👈 מחזיר אותנו להצגת הסל
    if (!this.cartData()?.items || this.cartData()?.items.length === 0) {
      return;
    }
    if (!this.userId) {
      alert("Please log in to complete the purchase.");
      return;
    }
    this.cartService.PurchaseCart(this.userId!).subscribe({
      next: (data) => {
        console.log("Purchase successful", data);
        this.confirmDialogVisible = false;

        this.loadCart();                 // מחדש את הסל שלא שולמה
      },
      error: (error) => {
        if (error.status === 500) {
          // כאן אפשר לבדוק את ההודעה שהשרת שלח
          console.error('Error purchasing cart:', error.error);
          alert("לא ניתן לבצע את ההזמנה ייתכן ואחת או יותר מהמתנות כבר הוגרלו"); // מציג את ההודעה למשתמש
        } else {
          console.error('Unexpected error', error);
        }
      }

    });;
    this.loadCart();                 // מחדש את הסל שלא שולמה
  }
  // הצגת דיאלוג אישור תשלום
  confirmPayment() {
    // this.showPaidOrders.set(false);  // 👈 מחזיר אותנו להצגת הסל
    // const total = this.cartData()?.items?.reduce((sum, item) => sum + item.ticketPrice * item.quantity, 0) || 0;
    // this.totalToPay.set(total);
    // console.log("Total to pay:", total);
    // this.confirmDialogVisible = true;  // 🟢 כאן
    if (!this.userId) return;
    this.fireConfetti(1000);

    this.router.navigateByUrl('/checkout')
  }
  private fireConfetti(durationMs = 800) {
    const canvas = this.confettiCanvas?.nativeElement;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dpr = window.devicePixelRatio || 1;
    const w = window.innerWidth;
    const h = window.innerHeight;

    canvas.style.display = 'block';
    canvas.width = Math.floor(w * dpr);
    canvas.height = Math.floor(h * dpr);
    canvas.style.width = w + 'px';
    canvas.style.height = h + 'px';
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

    const pieces = Array.from({ length: 110 }).map(() => ({
      x: Math.random() * w,
      y: -20 - Math.random() * h * 0.25,
      r: 2 + Math.random() * 4,
      vx: -2 + Math.random() * 4,
      vy: 2 + Math.random() * 5,
      rot: Math.random() * Math.PI,
      vrot: -0.2 + Math.random() * 0.4,
      color: `hsl(${Math.floor(Math.random() * 360)}, 90%, 55%)`
    }));

    const start = performance.now();

    const tick = (t: number) => {
      const elapsed = t - start;
      ctx.clearRect(0, 0, w, h);

      for (const p of pieces) {
        p.x += p.vx;
        p.y += p.vy;
        p.rot += p.vrot;
        p.vy += 0.06;

        ctx.save();
        ctx.translate(p.x, p.y);
        ctx.rotate(p.rot);
        ctx.fillStyle = p.color;
        ctx.fillRect(-p.r, -p.r, p.r * 2, p.r * 2);
        ctx.restore();
      }

      if (elapsed < durationMs) requestAnimationFrame(tick);
      else {
        ctx.clearRect(0, 0, w, h);
        canvas.style.display = 'none';
      }
    };

    requestAnimationFrame(tick);
  }

}
